76	/**
77	 * Read dependencies.json synchronously (used inside sort comparator).
78	 */
79	function readDependenciesSync(trackerDir: string): DependenciesFile {
80	  const contents = readFileSync(join(trackerDir, "dependencies.json"), "utf-8");
81	  return JSON.parse(contents) as DependenciesFile;
