125	/**
126	 * Recursively auto-close done children when a parent is closed.
127	 * Appends system-authored events to each child's issue file and updates the index.
128	 * Returns the updated index.
129	 */
130	async function cascadeClose(
131	  index: IndexFile,
132	  issueId: IssueId,
133	  trackerDir: string,
134	): Promise<IndexFile> {
135	  const childIds = getChildren(index, issueId);
136	  let currentIndex = index;
137	
138	  for (const childId of childIds) {
139	    const childEntry = findEntry(currentIndex, childId);
140	    if (!childEntry || childEntry.status !== "done") continue;
141	
142	    const now = new Date().toISOString();
143	    const event: Event = {
144	      type: "update",
145	      timestamp: now,
146	      author: "system",
147	      content: {
148	        status: "closed",
149	        reason: "auto-closed: parent closed",
150	      },
151	    };
152	
153	    const childPath = join(trackerDir, childEntry.path);
154	    await appendEvent(childPath, event);
155	
156	    currentIndex = updateEntry(currentIndex, childId, { status: "closed" });
157	
158	    // Recursively cascade to the child's own children
159	    currentIndex = await cascadeClose(currentIndex, childId, trackerDir);
160	  }
161	
162	  return currentIndex;
163	}
