165	/**
166	 * Tracker — the main programmatic API for trackgentic.
167	 *
168	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
169	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
170	 */
171	export class Tracker {
172	  private cwd: string;
173	
174	  constructor(cwd?: string) {
175	    this.cwd = cwd ?? process.cwd();
176	  }
177	
178	  /**
179	   * Initialize a new `.trackgentic/` directory in `cwd`.
180	   */
181	  async init(): Promise<InitResult> {
182	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
183	
184	    if (existsSync(trackerDir)) {
185	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
186	    }
187	
188	    mkdirSync(trackerDir, { recursive: true });
189	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
190	
191	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
192	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
193	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
194	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
195	
196	    return { result: "OK", path: resolve(trackerDir) };
197	  }
198	
199	  /**
200	   * Create a new issue.
201	   */
202	  async create(params: CreateParams): Promise<CreateResult> {
203	    const trackerDir = resolveTrackerDir(this.cwd);
204	    if (!trackerDir) {
205	      throw new TrackgenticError(
206	        ErrorCodes.NOT_INITIALIZED.result,
207	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
208	        ErrorCodes.NOT_INITIALIZED.exitCode,
209	      );
210	    }
211	
212	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
213	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
214	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
215	    if (authResult instanceof TrackgenticError) return authResult;
216	    const author = params.author ?? authResult.author;
217	
218	    const id = generateId();
219	    const issuePath = params.path ?? `issues/${id}.json`;
220	    const now = new Date().toISOString();
221	
222	    const title = params.title;
223	    const description = params.description ?? "";
224	    const status: IssueStatus = params.status ?? "idea";
225	    const priority = params.priority ?? 3;
226	    const assignee = params.assignee ?? null;
227	    const parentId = params.parentId ?? null;
228	    const tags = params.tags ?? [];
229	
230	    // Read index early for parent validation
231	    const index = await readIndex(trackerDir);
232	
233	    // Validate parent exists and is not closed
234	    if (parentId) {
235	      const parentEntry = findEntry(index, parentId);
236	      if (!parentEntry) {
237	        throw new TrackgenticError(
238	          ErrorCodes.NOT_FOUND.result,
239	          "Parent issue not found",
240	          ErrorCodes.NOT_FOUND.exitCode,
241	        );
242	      }
243	      const validationError = validateNewChild(parentEntry);
244	      if (validationError) {
245	        throw new TrackgenticError(
246	          ErrorCodes.HIERARCHY_CONSTRAINT.result,
247	          validationError,
248	          ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
249	        );
250	      }
251	    }
252	
253	    // Build update content with only non-default values
254	    const updateContent: Partial<
255	      Pick<
256	        IssueProperties,
257	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
258	      >
259	    > & { title: string } = { title };
260	    if (description) updateContent.description = description;
261	    if (status !== "idea") updateContent.status = status;
262	    if (priority !== 3) updateContent.priority = priority;
263	    if (assignee !== null) updateContent.assignee = assignee;
264	    if (parentId !== null) updateContent.parentId = parentId;
265	    if (tags.length > 0) updateContent.tags = tags;
266	
267	    // Create issue file with two events: creation + update
268	    const creationEvent = { type: "creation" as const, timestamp: now, author };
269	    const updateEvent = {
270	      type: "update" as const,
271	      timestamp: now,
272	      author,
273	      content: updateContent,
274	    };
275	
276	    const issueFilePath = join(trackerDir, issuePath);
277	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
278	
279	    // Build index entry and insert into index
280	    const entry: IndexEntry = {
281	      id,
282	      title,
283	      path: issuePath,
284	      status,
285	      assignee,
286	      parentId,
287	      tags,
288	      priority,
289	    };
290	
291	    const updatedIndex = insertEntry(index, entry);
292	    await writeIndex(trackerDir, updatedIndex);
293	
294	    return { id };
295	  }
