297	  /**
298	   * List issues from the index, with optional filters.
299	   */
300	  async list(params?: ListParams): Promise<ListResult> {
301	    const trackerDir = resolveTrackerDir(this.cwd);
302	    if (!trackerDir) {
303	      throw new TrackgenticError(
304	        ErrorCodes.NOT_INITIALIZED.result,
305	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
306	        ErrorCodes.NOT_INITIALIZED.exitCode,
307	      );
308	    }
309	
310	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
311	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
312	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
313	    if (authResult instanceof TrackgenticError) {
314	      throw authResult;
315	    }
316	
317	    const index = await readIndex(trackerDir);
318	
319	    // Determine source arrays based on params.status
320	    let entries: IndexEntry[];
321	    if (params?.status === "closed") {
322	      entries = index.closed;
323	    } else if (params?.status === "open") {
324	      entries = index.open;
325	    } else if (params?.status) {
326	      entries = index.open;
327	    } else {
328	      entries = [...index.open, ...index.closed];
329	    }
330	
331	    // Filter in memory
332	    let filtered = entries;
333	
334	    if (params?.status && params.status !== "open" && params.status !== "closed") {
335	      filtered = filtered.filter((e) => e.status === params.status);
336	    }
337	
338	    if (params?.assignee) {
339	      filtered = filtered.filter((e) => e.assignee === params.assignee);
340	    }
341	
342	    if (params?.tags && params.tags.length > 0) {
343	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
344	    }
345	
346	    if (params?.parentId !== undefined) {
347	      if (params.parentId === null) {
348	        filtered = filtered.filter((e) => e.parentId === null);
349	      } else {
350	        filtered = filtered.filter((e) => e.parentId === params.parentId);
351	      }
352	    }
353	
354	    // Read dependencies once for impact score
355	    let deps: DependenciesFile | null = null;
356	
357	    // Sort: priority ASC → impact DESC → id ASC
358	    filtered.sort((a, b) => {
359	      if (a.priority !== b.priority) return a.priority - b.priority;
360	      // Lazy-load deps only once for sorting
361	      if (!deps) {
362	        deps = readDependenciesSync(trackerDir);
363	      }
364	      const impactA = getImpactScore(deps, a.id);
365	      const impactB = getImpactScore(deps, b.id);
366	      if (impactA !== impactB) return impactB - impactA;
367	      return a.id.localeCompare(b.id);
368	    });
369	
370	    return filtered;
371	  }
