/**
 * Issue ID — 10-char string: 6 from timestamp base36 + 4 random base36.
 * Sortable by creation time.
 */
export type IssueId = string;

/**
 * Comment ID — same format as IssueId: 10-char base36 string.
 */
export type CommentId = string;

/**
 * Issue status progression: idea → todo → in-progress → done → closed.
 */
export type IssueStatus = "idea" | "todo" | "in-progress" | "done" | "closed";

/**
 * Mutable properties of an issue, reconstructed by replaying events.
 */
export interface IssueProperties {
  id: IssueId;
  title: string;
  description: string;
  status: IssueStatus;
  assignee: string | null;
  parentId: IssueId | null;
  tags: string[];
  priority: 1 | 2 | 3 | 4 | 5;
}

/**
 * Full computed state of an issue, including timestamps.
 * Produced by replaying all events for an issue.
 */
export interface ComputedIssue extends IssueProperties {
  /** ISO 8601 — timestamp of the creation event. */
  createdAt: string;
  /** Author of the creation event. */
  createdBy: string;
  /** ISO 8601 — timestamp of the last event. */
  updatedAt: string;
}

/**
 * Computed state of a single comment.
 * Produced by replaying comment, comment-update, and comment-delete events.
 */
export interface ComputedComment {
  id: CommentId;
  author: string;
  content: string;
  /** ISO 8601 — when the comment was created. */
  timestamp: string;
  /** ISO 8601 — when the last comment-update was applied, or null if never edited. */
  editedAt: string | null;
}

import type { CommentId, IssueId, IssueProperties } from "./issue";

/**
 * Base shape shared by all events.
 */
export interface BaseEvent {
  /** ISO 8601 timestamp. */
  timestamp: string;
  /** Resolved user name or "system". */
  author: string;
}

/**
 * Creation event — marks the birth of an issue.
 * Always the first event in an issue file.
 */
export interface CreationEvent extends BaseEvent {
  type: "creation";
}

/**
 * Update event — records changes to issue properties.
 * Includes an optional reason field for system-authored auto-promotion events.
 */
export interface UpdateEvent extends BaseEvent {
  type: "update";
  content: Partial<
    Pick<
      IssueProperties,
      "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
    >
  > & {
    /** Optional reason explaining why the update was applied (e.g. auto-promotion). */
    reason?: string;
  };
}

/**
 * Comment event — adds a new comment to an issue.
 */
export interface CommentEvent extends BaseEvent {
  type: "comment";
  content: {
    id: CommentId;
    content: string;
  };
}

/**
 * Comment update event — edits an existing comment's content.
 */
export interface CommentUpdateEvent extends BaseEvent {
  type: "comment-update";
  content: {
    id: CommentId;
    content: string;
  };
}

/**
 * Comment delete event — soft-deletes a comment.
 * Deleted comments are excluded from computed output but remain in the event log.
 */
export interface CommentDeleteEvent extends BaseEvent {
  type: "comment-delete";
  content: {
    id: CommentId;
  };
}

/**
 * Blockage added event — records a new dependency between two issues.
 */
export interface BlockageAddedEvent extends BaseEvent {
  type: "blockage-added";
  content: {
    blockerId: IssueId;
  };
}

/**
 * Blockage resolved event — records dependency resolution.
 * Includes an optional reason for why the blockage was resolved.
 */
export interface BlockageResolvedEvent extends BaseEvent {
  type: "blockage-resolved";
  content: {
    blockerId: IssueId;
    reason?: string;
  };
}

/**
 * Blockage deleted event — records dependency removal.
