  | UpdateEvent
  | CommentEvent
  | CommentUpdateEvent
  | CommentDeleteEvent
  | BlockageAddedEvent
  | BlockageResolvedEvent
  | BlockageDeletedEvent;

import type { IssueId, IssueStatus } from "./issue";

/**
 * Summary of an issue for fast index lookup.
