export interface IndexEntry {
  id: IssueId;
  title: string;
  /** Relative path to the issue file from the tracker directory. */
  path: string;
  status: IssueStatus;
  assignee: string | null;
  parentId: IssueId | null;
  tags: string[];
  priority: 1 | 2 | 3 | 4 | 5;
}

/**
 * Index file structure — two sorted arrays and a children map.
 *
 * Invariants:
 * - Both arrays are sorted by issue id (time-sortable).
 * - `open` contains entries where status !== "closed".
 * - `closed` contains entries where status === "closed".
 * - `childrenOf` keys only exist for issues that have children.
 */
export interface IndexFile {
  /** Issues that are not closed. */
  open: IndexEntry[];
  /** Issues that are closed. */
  closed: IndexEntry[];
  /** Maps parent ID to array of child IDs. */
  childrenOf: Record<IssueId, IssueId[]>;
}

import type { IssueId } from "./issue";

/**
 * A single blockage relationship between two issues.
 * A blockage means the blocked issue cannot proceed until the blocker is resolved.
 */
export interface BlockageEntry {
  blockerId: IssueId;
  blockedId: IssueId;
  status: "active" | "resolved";
}

/**
 * Dependencies file — bidirectional blockage maps.
 * Both maps are always kept in sync. Every mutation writes both sides atomically.
 */
export interface DependenciesFile {
  /** Maps issue ID → list of issues blocking it. */
  blockedBy: Record<IssueId, BlockageEntry[]>;
  /** Maps issue ID → list of issues it blocks. */
  blocks: Record<IssueId, BlockageEntry[]>;
}

/**
 * Blockage info for a specific issue, returned by the view/blockagesList endpoint.
 */
export interface BlockageInfo {
  issueId: IssueId;
  /** Issues that are blocking this issue. */
  blockedBy: BlockageEntry[];
  /** Issues that this issue is blocking. */
  blocks: BlockageEntry[];
}

/**
 * A single registered user with their authentication token.
 */
export interface UserEntry {
  /** Stored lowercase for case-insensitive lookup. */
  name: string;
  /** Format: tk_ + 8 random alphanumeric characters. */
  token: string;
  /** ISO 8601 — when the user was registered. */
  registeredAt: string;
}

/**
 * Users file — list of registered users.
 * Stored at `.trackgentic/users.json`.
 */
export interface UsersFile {
  users: UserEntry[];
}

/**
 * Public user info without the token.
 * Returned by usersList to prevent token leakage.
 */
export interface UserInfo {
  name: string;
  /** ISO 8601 — when the user was registered. */
  registeredAt: string;
}

/**
 * Configuration file stored at `.trackgentic/config.json`.
 * Controls authentication behavior for all operations.
 */
export interface ConfigFile {
  auth: {
    /** Authentication mode:
     * - "open" — no auth required, uses default user
     * - "read-only" — auth required for writes, reads use default user
     * - "strict" — auth required for all operations
