416	  /**
417	   * Update an existing issue.
418	   */
419	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
420	    const trackerDir = resolveTrackerDir(this.cwd);
421	    if (!trackerDir) {
422	      throw new TrackgenticError(
423	        ErrorCodes.NOT_INITIALIZED.result,
424	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
425	        ErrorCodes.NOT_INITIALIZED.exitCode,
426	      );
427	    }
428	
429	    // Validate at least one field provided (besides author)
430	    const hasField =
431	      params.title !== undefined ||
432	      params.description !== undefined ||
433	      params.status !== undefined ||
434	      params.assignee !== undefined ||
435	      params.tags !== undefined ||
436	      params.priority !== undefined ||
437	      params.parentId !== undefined;
438	
439	    if (!hasField) {
440	      throw new TrackgenticError(
441	        ErrorCodes.INVALID_PARAMS.result,
442	        "At least one field must be provided for update.",
443	        ErrorCodes.INVALID_PARAMS.exitCode,
444	      );
445	    }
446	
447	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
448	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
449	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
450	    if (authResult instanceof TrackgenticError) return authResult;
451	    const author = params.author ?? authResult.author;
452	
453	    const index = await readIndex(trackerDir);
454	    const entry = findEntry(index, id);
455	    if (!entry) {
456	      throw new TrackgenticError(
457	        ErrorCodes.NOT_FOUND.result,
458	        `Issue \`${id}\` not found in index.`,
459	        ErrorCodes.NOT_FOUND.exitCode,
460	      );
461	    }
462	
463	    const issueFilePath = join(trackerDir, entry.path);
464	    if (!existsSync(issueFilePath)) {
465	      throw new TrackgenticError(
466	        ErrorCodes.ISSUE_MISSING.result,
467	        `Issue file for \`${id}\` is missing.`,
468	        ErrorCodes.ISSUE_MISSING.exitCode,
469	      );
470	    }
471	
472	    // Save old values for hierarchy handling
473	    const oldStatus = entry.status;
474	    const oldParentId = entry.parentId;
475	
476	    // ── Hierarchy validation (before any state changes) ────────────
477	
478	    // Validate downward constraints for status change
479	    if (params.status !== undefined && params.status !== oldStatus) {
480	      if (params.status === "done" || params.status === "closed") {
481	        const childIds = getChildren(index, id);
482	        const childEntries = childIds
483	          .map((cid) => findEntry(index, cid))
484	          .filter((e): e is IndexEntry => e !== null);
485	        const validationError = validateParentStatusChange(index, childEntries, params.status);
486	        if (validationError) {
487	          throw new TrackgenticError(
488	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
489	            validationError,
490	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
491	          );
492	        }
493	      }
494	    }
495	
496	    // Validate reparenting constraints
497	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
498	      if (params.parentId !== null) {
499	        const newParentEntry = findEntry(index, params.parentId);
500	        if (!newParentEntry) {
501	          throw new TrackgenticError(
502	            ErrorCodes.NOT_FOUND.result,
503	            `Parent issue \`${params.parentId}\` not found in index.`,
504	            ErrorCodes.NOT_FOUND.exitCode,
505	          );
506	        }
507	        const validationError = validateNewChild(newParentEntry);
508	        if (validationError) {
509	          throw new TrackgenticError(
510	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
511	            validationError,
512	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
513	          );
514	        }
515	      }
516	    }
517	
518	    // ── Build and append update event ──────────────────────────────
519	
520	    // Build update event content with only the provided fields
521	    const content: Partial<
522	      Pick<
523	        IssueProperties,
524	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
525	      >
526	    > = {};
527	    if (params.title !== undefined) content.title = params.title;
528	    if (params.description !== undefined) content.description = params.description;
529	    if (params.status !== undefined) content.status = params.status;
530	    if (params.assignee !== undefined) content.assignee = params.assignee;
531	    if (params.tags !== undefined) content.tags = params.tags;
532	    if (params.priority !== undefined) content.priority = params.priority;
533	    if (params.parentId !== undefined) content.parentId = params.parentId;
534	
535	    const now = new Date().toISOString();
536	
537	    const updateEvent = {
538	      type: "update" as const,
539	      timestamp: now,
540	      author,
541	      content,
542	    };
543	
544	    // Append event to issue file
545	    await appendEvent(issueFilePath, updateEvent);
546	
547	    // Recompute state from all events
548	    const events = await replayEvents(issueFilePath);
549	    const computed = computeState(events, id);
550	
551	    // Update index entry with new computed values
552	    let updatedIndex = updateEntry(index, id, {
553	      title: computed.title,
554	      status: computed.status,
555	      assignee: computed.assignee,
556	      parentId: computed.parentId,
557	      tags: computed.tags,
558	      priority: computed.priority,
559	    });
560	
561	    // ── Hierarchy handling (after event append, before index write) ─
562	
563	    // 1. Handle reparenting (childrenOf updates)
564	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
565	      // Detach from old parent
566	      if (oldParentId !== null) {
567	        updatedIndex = removeChild(updatedIndex, oldParentId, id);
568	      }
569	      // Attach to new parent
570	      if (params.parentId !== null) {
571	        updatedIndex = addChild(updatedIndex, params.parentId, id);
572	
573	        // Upward promotion for reparenting: if child's status is past new parent's status
574	        const newParentEntry = findEntry(updatedIndex, params.parentId);
575	        if (newParentEntry && isStatusAfter(computed.status, newParentEntry.status)) {
576	          const promotions = computeUpwardPromotions(
577	            updatedIndex,
578	            newParentEntry,
579	            computed.status,
580	            (iid) => findEntry(updatedIndex, iid),
581	          );
582	          for (const promo of promotions) {
583	            const promoEntry = findEntry(updatedIndex, promo.issueId);
584	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
585	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
586	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
587	                status: promo.event.content.status,
588	              });
589	            }
590	          }
591	        }
592	      }
593	    }
594	
595	    // 2. Handle status change
596	    if (params.status !== undefined && params.status !== oldStatus) {
597	      // Downward cascade: auto-close done children when parent closes
598	      if (params.status === "closed") {
599	        updatedIndex = await cascadeClose(updatedIndex, id, trackerDir);
600	      }
601	
602	      // Upward promotion: promote parent if child advanced past it
603	      const currentParentId = computed.parentId;
604	      if (currentParentId) {
605	        const parentEntry = findEntry(updatedIndex, currentParentId);
606	        if (parentEntry && isStatusAfter(params.status, parentEntry.status)) {
607	          const promotions = computeUpwardPromotions(
608	            updatedIndex,
609	            parentEntry,
610	            params.status,
611	            (iid) => findEntry(updatedIndex, iid),
612	          );
613	          for (const promo of promotions) {
614	            const promoEntry = findEntry(updatedIndex, promo.issueId);
615	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
616	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
617	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
618	                status: promo.event.content.status,
619	              });
620	            }
621	          }
622	        }
623	      }
624	    }
625	
626	    await writeIndex(trackerDir, updatedIndex);
627	
628	    // ── Auto-resolution: resolve active blockages when issue → done/closed ──
629	    if (params.status !== undefined && params.status !== oldStatus) {
630	      if (params.status === "done" || params.status === "closed") {
631	        const deps = await readDependencies(trackerDir);
632	        const activeBlocks = (deps.blocks[id] ?? []).filter((e) => e.status === "active");
633	
634	        if (activeBlocks.length > 0) {
635	          let updatedDeps = deps;
636	          for (const entry of activeBlocks) {
637	            updatedDeps = resolveBlockage(updatedDeps, entry.blockedId, entry.blockerId);
638	
639	            const blockedEntry = findEntry(updatedIndex, entry.blockedId);
640	            if (blockedEntry) {
641	              const now = new Date().toISOString();
642	              const resolveEvent: Event = {
643	                type: "blockage-resolved",
644	                timestamp: now,
645	                author: "system",
646	                content: {
647	                  blockerId: id,
648	                  reason: `Blocker issue ${id} transitioned to ${params.status}`,
649	                },
650	              };
651	              await appendEvent(join(trackerDir, blockedEntry.path), resolveEvent);
652	            }
653	          }
654	          await writeDependencies(trackerDir, updatedDeps);
655	        }
656	      }
657	    }
658	
659	    return { result: "OK" };
660	  }
